1	/**
2	 * KRN-V3-05 — Stair by sketch authoring overlay.
3	 *
4	 * Two-phase drawing:
5	 *   Phase A (boundary): user draws a closed polygon for the stair footprint.
6	 *   Phase B (tread_lines): user draws lines across the boundary; a live
7	 *   comfort advisory shows EU residential proxy compliance.
8	 *
9	 * On Finish the component opens a stair_by_sketch sketch session, immediately
10	 * finishes it with the assembled StairSketchFinishOpts, and reports the new
11	 * stair id via onFinished.
12	 *
13	 * All colours and sizes use CSS tokens — no hex literals (ESLint bim-ai/no-hex-in-chrome).
14	 */
15	
16	import { type JSX, type RefObject, useCallback, useEffect, useRef, useState } from 'react';
17	
18	import {
19	  cancelSketchSession,
20	  finishSketchSession,
21	  openSketchSession,
22	  type StairSketchFinishOpts,
23	} from './sketchApi';
24	import type { MmToScreen, Point2D, PointerToMm } from './SketchCanvas';
25	
26	export interface StairBySketchCanvasProps {
27	  modelId: string;
28	  levelId: string;
29	  topLevelId: string;
30	  /** Elevation of baseLevelId in mm. */
31	  baseLevelElevationMm: number;
32	  /** Elevation of topLevelId in mm. */
33	  topLevelElevationMm: number;
34	  pointerToMmRef: RefObject<PointerToMm | null>;
35	  mmToScreenRef: RefObject<MmToScreen | null>;
36	  onFinished: (createdId: string | null) => void;
37	  onCancelled: () => void;
38	}
39	
40	type Phase = 'boundary' | 'tread_lines';
41	
42	type TreadLine = { fromMm: Point2D; toMm: Point2D };
43	
44	const SNAP_GRID_MM = 10;
45	const CLOSE_EPS_PX = 12;
46	const MIN_TREAD_MM = 260;
47	const MAX_RISER_MM = 190;
48	
49	function snapMm(p: Point2D): Point2D {
50	  return {
51	    xMm: Math.round(p.xMm / SNAP_GRID_MM) * SNAP_GRID_MM,
52	    yMm: Math.round(p.yMm / SNAP_GRID_MM) * SNAP_GRID_MM,
53	  };
54	}
55	
56	function distPx(a: { x: number; y: number }, b: { x: number; y: number }): number {
57	  return Math.sqrt((a.x - b.x) ** 2 + (a.y - b.y) ** 2);
58	}
59	
60	function avgTreadDepthMm(lines: TreadLine[]): number {
61	  if (lines.length < 2) return 0;
62	  let total = 0;
63	  for (let i = 0; i < lines.length - 1; i++) {
64	    const a = lines[i]!;
65	    const b = lines[i + 1]!;
66	    const midAx = (a.fromMm.xMm + a.toMm.xMm) / 2;
67	    const midAy = (a.fromMm.yMm + a.toMm.yMm) / 2;
68	    const midBx = (b.fromMm.xMm + b.toMm.xMm) / 2;
69	    const midBy = (b.fromMm.yMm + b.toMm.yMm) / 2;
70	    total += Math.sqrt((midBx - midAx) ** 2 + (midBy - midAy) ** 2);
71	  }
72	  return total / (lines.length - 1);
73	}
74	
75	export function StairBySketchCanvas(props: StairBySketchCanvasProps): JSX.Element {
76	  const {
77	    modelId,
78	    levelId,
79	    topLevelId,
80	    baseLevelElevationMm,
81	    topLevelElevationMm,
82	    pointerToMmRef,
83	    mmToScreenRef,
84	    onFinished,
85	    onCancelled,
86	  } = props;
87	
88	  const totalRiseMm = Math.abs(topLevelElevationMm - baseLevelElevationMm);
89	
90	  const [phase, setPhase] = useState<Phase>('boundary');
91	  const [boundary, setBoundary] = useState<Point2D[]>([]);
92	  const [treadLines, setTreadLines] = useState<TreadLine[]>([]);
93	  const [hover, setHover] = useState<Point2D | null>(null);
94	  const [lineStart, setLineStart] = useState<Point2D | null>(null);
95	  const [sessionId, setSessionId] = useState<string | null>(null);
96	  const [busy, setBusy] = useState(false);
97	  const [, setTick] = useState(0);
98	  const overlayRef = useRef<HTMLDivElement | null>(null);
99	
100	  // Open stair_by_sketch session on mount.
101	  useEffect(() => {
102	    let cancelled = false;
103	    openSketchSession(modelId, levelId, { elementKind: 'stair_by_sketch' })
104	      .then((resp) => {
105	        if (!cancelled) setSessionId(resp.session.sessionId);
106	      })
107	      .catch(() => {
108	        if (!cancelled) onCancelled();
109	      });
110	    return () => {
111	      cancelled = true;
112	    };
113	  }, [modelId, levelId, onCancelled]);
114	
115	  // Force re-render on animation frame so screen coords track pan/zoom.
116	  useEffect(() => {
117	    let rafId: number;
118	    const tick = () => {
119	      setTick((n) => n + 1);
120	      rafId = requestAnimationFrame(tick);
121	    };
122	    rafId = requestAnimationFrame(tick);
123	    return () => cancelAnimationFrame(rafId);
124	  }, []);
125	
126	  const toScreen = useCallback((p: Point2D) => mmToScreenRef.current?.(p) ?? null, [mmToScreenRef]);
127	  const toMm = useCallback(
128	    (cx: number, cy: number) => pointerToMmRef.current?.(cx, cy) ?? null,
129	    [pointerToMmRef],
130	  );
131	
132	  const handlePointerMove = useCallback(
133	    (e: React.PointerEvent<HTMLDivElement>) => {
134	      const mm = toMm(e.clientX, e.clientY);
135	      if (mm) setHover(snapMm(mm));
136	    },
137	    [toMm],
138	  );
139	
140	  const handlePointerLeave = useCallback(() => setHover(null), []);
141	
142	  const handleClick = useCallback(
143	    (e: React.MouseEvent<HTMLDivElement>) => {
144	      const mm = toMm(e.clientX, e.clientY);
145	      if (!mm) return;
146	      const snapped = snapMm(mm);
147	
148	      if (phase === 'boundary') {
149	        if (boundary.length >= 3) {
150	          // Check if click is near the first vertex (close polygon).
